import{_ as o,o as a,c as t,af as r}from"./chunks/framework.DZTH9Z-c.js";const u=JSON.parse('{"title":"История изменений","description":"Changelog Coreness. Последние изменения, новые функции, breaking changes и миграции между версиями.","frontmatter":{"title":"История изменений","description":"Changelog Coreness. Последние изменения, новые функции, breaking changes и миграции между версиями.","keywords":"changelog coreness, история изменений, обновления, breaking changes, миграция","head":[["meta",{"property":"og:title","content":"История изменений | Coreness"}],["meta",{"property":"og:description","content":"Changelog Coreness. Последние изменения, новые функции, breaking changes и миграции между версиями."}],["meta",{"property":"og:image","content":"https://docs.coreness.tech/logo-dark.png"}],["meta",{"property":"og:url","content":"https://docs.coreness.tech/CHANGELOG"}],["link",{"rel":"canonical","href":"https://docs.coreness.tech/CHANGELOG"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"История изменений\\",\\"description\\":\\"Changelog Coreness. Последние изменения, новые функции, breaking changes и миграции между версиями.\\",\\"url\\":\\"https://docs.coreness.tech/CHANGELOG\\"}"]]},"headers":[],"relativePath":"CHANGELOG.md","filePath":"CHANGELOG.md"}'),i={name:"CHANGELOG.md"};function l(d,e,n,c,s,h){return a(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Все важные изменения в проекте документируются в этом файле.</p><h2 id="_1-1-2-2026-02-08" tabindex="-1">[1.1.2] - 2026-02-08 <a class="header-anchor" href="#_1-1-2-2026-02-08" aria-label="Permalink to &quot;[1.1.2] - 2026-02-08&quot;">​</a></h2><h3 id="⚠️-breaking-changes" tabindex="-1">⚠️ BREAKING CHANGES <a class="header-anchor" href="#⚠️-breaking-changes" aria-label="Permalink to &quot;⚠️ BREAKING CHANGES&quot;">​</a></h3><ul><li><strong>Структура конфигурации тенанта:</strong> файл <code>tg_bot.yaml</code> в корне тенанта заменён на папку <code>bots/</code> с конфигами ботов. Конфиг Telegram-бота теперь хранится в <code>bots/telegram.yaml</code>. В папке <code>bots/</code> могут быть конфиги для разных ботов (например, <code>telegram.yaml</code>, <code>whatsapp.yaml</code>).</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Обновлена и улучшена документация: структура разделов, навигация, формулировки</li><li>Переработана структура хабов: tenant_hub и сервис управления ботами (ранее условно «bot hub»); управление ботами теперь сосредоточено в сервисе Telegram (telegram_bot_manager)</li></ul><h3 id="technical-improvements" tabindex="-1">Technical Improvements <a class="header-anchor" href="#technical-improvements" aria-label="Permalink to &quot;Technical Improvements&quot;">​</a></h3><ul><li>Рефакторинг tenant_hub: вынесены обработчики действий (actions), объединена логика GitHub-синхронизации, переименованы domain-модули (utils → domain, TenantDataManager → TenantRepository)</li></ul><h2 id="_1-1-1-2026-02-04" tabindex="-1">[1.1.1] - 2026-02-04 <a class="header-anchor" href="#_1-1-1-2026-02-04" aria-label="Permalink to &quot;[1.1.1] - 2026-02-04&quot;">​</a></h2><h3 id="changed-1" tabindex="-1">Changed <a class="header-anchor" href="#changed-1" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Документация: быстрый старт переведён на системные тенанты (без GitHub); публичные тенанты — отдельный блок</li><li>Конфигурация: граница системных тенантов — до 99 (<code>max_system_tenant_id: 99</code> в <code>config/settings.yaml</code>), 100 и выше — публичные</li><li>При отсутствующем <code>github_url</code> ошибки не выводятся, синхронизация пропускается, система работает только с системными тенантами</li><li>Тенант 1 (мастер бот): переработан сценарий — поддержка выбора языка (i18n), облегчён и улучшен UX, улучшена документация.</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Общие улучшения системы и небольшие исправления</li></ul><h3 id="technical-improvements-1" tabindex="-1">Technical Improvements <a class="header-anchor" href="#technical-improvements-1" aria-label="Permalink to &quot;Technical Improvements&quot;">​</a></h3><ul><li>Система бэкапов: упрощено управление бэкапами — разделение по типам БД в отдельные папки (sqlite/, postgresql/), добавлено сжатие (gzip для SQLite, pg_dump -Z 9 для PostgreSQL), унификация форматов между утилитой и плагином</li></ul><h2 id="_1-1-0-2026-02-02" tabindex="-1">[1.1.0] - 2026-02-02 <a class="header-anchor" href="#_1-1-0-2026-02-02" aria-label="Permalink to &quot;[1.1.0] - 2026-02-02&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>В гайде по действиям (ACTION_GUIDE): маркировка действий из плагинов-расширений (⭐) в оглавлении и в заголовках секций, примечание о расширениях</li><li>В документацию добавлено описание расширений (действия из папки extensions)</li></ul><h3 id="changed-2" tabindex="-1">Changed <a class="header-anchor" href="#changed-2" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li>Улучшена документация</li><li>Гайд по развёртыванию (DEPLOYMENT.md) полностью обновлён под утилиту Core Manager</li></ul><h3 id="technical-improvements-2" tabindex="-1">Technical Improvements <a class="header-anchor" href="#technical-improvements-2" aria-label="Permalink to &quot;Technical Improvements&quot;">​</a></h3><ul><li>Утилита развёртывания полностью переработана: заменена на Core Manager (<code>tools/core_manager</code>). Реализована полная поддержка двух языков (EN/RU), оптимизирована структура и логика, улучшен UI/UX, доработано самообновление утилиты. Гайд по развёртыванию приведён в соответствие с новой утилитой</li></ul><h2 id="_1-0-3-2026-01-21" tabindex="-1">[1.0.3] - 2026-01-21 <a class="header-anchor" href="#_1-0-3-2026-01-21" aria-label="Permalink to &quot;[1.0.3] - 2026-01-21&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Добавлен гайд по моделям AI на английском языке (<code>docs/en/AI_MODELS_GUIDE.md</code>)</li><li>Добавлена полная английская версия документации — все основные гайды доступны в <code>docs/en/</code></li><li>Все конфигурационные файлы и комментарии в коде переведены на английский язык</li></ul><h3 id="technical-improvements-3" tabindex="-1">Technical Improvements <a class="header-anchor" href="#technical-improvements-3" aria-label="Permalink to &quot;Technical Improvements&quot;">​</a></h3><ul><li>Создан уровень <code>extensions</code> для плагинов — позволяет легко добавлять дополнительные плагины для расширения функционала платформы, которые не затираются при обновлении</li><li>Обновлена документация по плагинам — добавлено описание системы расширений и правил их использования</li></ul><h2 id="_1-0-2-2026-01-16" tabindex="-1">[1.0.2] - 2026-01-16 <a class="header-anchor" href="#_1-0-2-2026-01-16" aria-label="Permalink to &quot;[1.0.2] - 2026-01-16&quot;">​</a></h2><h3 id="⚠️-breaking-changes-1" tabindex="-1">⚠️ BREAKING CHANGES <a class="header-anchor" href="#⚠️-breaking-changes-1" aria-label="Permalink to &quot;⚠️ BREAKING CHANGES&quot;">​</a></h3><ul><li><strong>Плейсхолдеры: Переименование модификатора <code>time</code> → <code>seconds</code></strong> — модификатор переименован для ясности и консистентности. Функционал не изменился, но синтаксис изменился: используйте <code>{duration|seconds}</code> вместо <code>{duration|time}</code> во всех сценариях</li><li><strong>Плейсхолдеры: Переименование форматов PostgreSQL <code>date_postgres</code>/<code>datetime_postgres</code> → <code>pg_date</code>/<code>pg_datetime</code></strong> — форматы переименованы для краткости. Обновите использование: <code>{timestamp|format:pg_date}</code> вместо <code>{timestamp|format:date_postgres}</code>, <code>{timestamp|format:pg_datetime}</code> вместо <code>{timestamp|format:datetime_postgres}</code></li></ul><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Плейсхолдеры: Поддержка литеральных значений в кавычках</strong> — теперь можно использовать значения напрямую в плейсхолдерах без передачи через словарь: <code>{&#39;hello&#39;|upper}</code>, <code>{&#39;1d 2w&#39;|seconds}</code>, <code>{&#39;100&#39;|+50}</code>. Поддерживаются одинарные и двойные кавычки с экранированием (<code>&#39;it\\&#39;s&#39;</code>, <code>&quot;say \\&quot;hi\\&quot;&quot;</code>)</li><li><strong>Плейсхолдеры: Модификатор <code>shift</code> для сдвига дат</strong> — новый модификатор для работы с датами в PostgreSQL стиле: <code>{created|shift:+1 day}</code>, <code>{created|shift:+1 year 2 months}</code>, <code>{created|shift:-2 hours}</code>. Поддерживает все форматы дат (PostgreSQL, стандартные, ISO, timestamp), корректно обрабатывает месяцы/годы и края месяцев (например, 31 янв + 1 месяц = 29 фев в високосном году)</li><li><strong>Плейсхолдеры: Модификаторы приведения дат к началу периода</strong> — новые модификаторы для приведения дат к началу различных периодов: <code>to_date</code> (начало дня), <code>to_hour</code> (начало часа), <code>to_minute</code> (начало минуты), <code>to_second</code> (начало секунды), <code>to_week</code> (начало недели - понедельник), <code>to_month</code> (начало месяца), <code>to_year</code> (начало года). Все возвращают ISO формат (<code>YYYY-MM-DD HH:MM:SS</code>). Примеры: <code>{created|to_date}</code>, <code>{created|to_month|format:date}</code></li></ul><h2 id="_1-0-1-2026-01-15" tabindex="-1">[1.0.1] - 2026-01-15 <a class="header-anchor" href="#_1-0-1-2026-01-15" aria-label="Permalink to &quot;[1.0.1] - 2026-01-15&quot;">​</a></h2><h3 id="fixed-1" tabindex="-1">Fixed <a class="header-anchor" href="#fixed-1" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li><code>get_tenants_list</code>: Все списки ID тенантов (<code>tenant_ids</code>, <code>public_tenant_ids</code>, <code>system_tenant_ids</code>) теперь возвращаются отсортированными по возрастанию</li></ul><h3 id="technical-improvements-4" tabindex="-1">Technical Improvements <a class="header-anchor" href="#technical-improvements-4" aria-label="Permalink to &quot;Technical Improvements&quot;">​</a></h3><ul><li>Упрощена утилита управления Docker (<code>docker/compose</code>) — убрано требование указания окружения для большинства команд, работа напрямую с контейнерами по имени (например, <code>dc logs app-test</code>, <code>dc start app-test</code>), улучшена команда <code>logs</code> с поддержкой tail и follow по умолчанию (последние 100 строк + follow)</li></ul><h2 id="_1-0-0-2025-12-31" tabindex="-1">[1.0.0] - 2025-12-31 <a class="header-anchor" href="#_1-0-0-2025-12-31" aria-label="Permalink to &quot;[1.0.0] - 2025-12-31&quot;">​</a></h2><h3 id="🎉-релиз-версии-1-0-0" tabindex="-1">🎉 Релиз версии 1.0.0 <a class="header-anchor" href="#🎉-релиз-версии-1-0-0" aria-label="Permalink to &quot;🎉 Релиз версии 1.0.0&quot;">​</a></h3><p>Платформа достигла стабильного состояния и готова к полноценному использованию в production окружении. За период разработки с версии 0.4.0 до 1.0.0 платформа претерпела значительные улучшения во всех ключевых аспектах.</p><h3 id="архитектура-и-инфраструктура" tabindex="-1">Архитектура и инфраструктура <a class="header-anchor" href="#архитектура-и-инфраструктура" aria-label="Permalink to &quot;Архитектура и инфраструктура&quot;">​</a></h3><ul><li><strong>Миграция на PostgreSQL</strong> — переход с SQLite на PostgreSQL для улучшения производительности, масштабируемости и надежности хранения данных</li><li><strong>Telegram вебхуки</strong> — поддержка вебхуков вместо пулинга с автоматической генерацией SSL-сертификатов</li><li><strong>Система деплоя</strong> — автоматизация деплоя через GitHub Actions, утилита управления деплоем с поддержкой миграций БД, бэкапов и версионирования</li><li><strong>Автоматические бэкапы</strong> — сервис фоновых бэкапов БД с настраиваемым интервалом и автоматической ротацией</li><li><strong>Database Access Control Views</strong> — система контроля доступа на уровне БД через PostgreSQL view</li><li><strong>GitHub вебхуки</strong> — автоматическая синхронизация тенантов при изменениях в репозитории</li></ul><h3 id="ai-и-rag-retrieval-augmented-generation" tabindex="-1">AI и RAG (Retrieval-Augmented Generation) <a class="header-anchor" href="#ai-и-rag-retrieval-augmented-generation" aria-label="Permalink to &quot;AI и RAG (Retrieval-Augmented Generation)&quot;">​</a></h3><ul><li><strong>Векторное хранилище</strong> — интеграция с pgvector для PostgreSQL, поддержка векторных embeddings размерностью 1024</li><li><strong>HNSW индекс</strong> — оптимизированный векторный поиск даже на больших объемах данных</li><li><strong>RAG действия</strong> — <code>save_embedding</code>, <code>search_embedding</code>, <code>get_recent_chunks</code>, <code>delete_embedding</code> для работы с векторным хранилищем</li><li><strong>Интеграция RAG в completion</strong> — параметр <code>rag_chunks</code> для автоматического формирования контекста из векторного поиска</li><li><strong>Миграция на Polza.ai</strong> — переход с OpenRouter на универсальный AI провайдер с поддержкой расширенного ценообразования и модальностей</li></ul><h3 id="сценарии-и-деиствия" tabindex="-1">Сценарии и действия <a class="header-anchor" href="#сценарии-и-деиствия" aria-label="Permalink to &quot;Сценарии и действия&quot;">​</a></h3><ul><li><strong>Унификация storage действий</strong> — единый набор действий для работы с Tenant Storage и User Storage (get/set/delete)</li><li><strong>Асинхронные действия</strong> — поддержка фонового выполнения долгих операций (например, запросы к LLM) с ожиданием через <code>wait_for_action</code></li><li><strong>Scheduled сценарии</strong> — запуск сценариев по расписанию через cron выражения</li><li><strong>Динамические клавиатуры</strong> — действие <code>build_keyboard</code> для создания клавиатур из массивов с шаблонами</li><li><strong>Централизованная валидация</strong> — единая система валидации входных параметров всех действий с структурированными ошибками</li><li><strong>Автоматическое преобразование типов</strong> — автоматическая конвертация типов параметров при необходимости</li><li><strong>Система кэширования</strong> — унифицированная утилита кэширования для всех критичных данных (боты, тенанты, сценарии, пользователи)</li></ul><h3 id="события-и-триггеры" tabindex="-1">События и триггеры <a class="header-anchor" href="#события-и-триггеры" aria-label="Permalink to &quot;События и триггеры&quot;">​</a></h3><ul><li><strong>Новые типы событий</strong> — события участников групп (<code>member_joined</code>, <code>member_left</code>), события платежей (<code>pre_checkout_query</code>, <code>payment_successful</code>)</li><li><strong>Улучшенные условия</strong> — поддержка маркера <code>$name</code> для полей в условиях, модификаторы для плейсхолдеров (<code>exists</code>, <code>is_null</code>, <code>code</code>, <code>keys</code>, <code>expand</code>)</li><li><strong>Плейсхолдеры</strong> — расширенная система плейсхолдеров с поддержкой сложных структур данных, точечной нотации и доступа к элементам массивов</li></ul><h3 id="хранилища-данных" tabindex="-1">Хранилища данных <a class="header-anchor" href="#хранилища-данных" aria-label="Permalink to &quot;Хранилища данных&quot;">​</a></h3><ul><li><strong>Tenant Storage</strong> — хранилище атрибутов тенанта (key-value) с поддержкой сложных структур (JSON объекты, массивы, вложенные структуры)</li><li><strong>User Storage</strong> — хранилище данных пользователя для хранения пользовательских настроек и данных</li><li><strong>Поиск по storage</strong> — действие <code>get_users_by_storage_value</code> для поиска пользователей по значениям в storage</li></ul><h3 id="платежи-и-инвоисы" tabindex="-1">Платежи и инвойсы <a class="header-anchor" href="#платежи-и-инвоисы" aria-label="Permalink to &quot;Платежи и инвойсы&quot;">​</a></h3><ul><li><strong>Сервис invoice_service</strong> — полный набор действий для работы с инвойсами: создание, отправка, подтверждение/отклонение платежей, получение информации, отмена</li><li><strong>Обработка платежей</strong> — автоматическая обработка событий <code>pre_checkout_query</code> и <code>payment_successful</code> для работы с Telegram Stars</li></ul><h3 id="улучшения-производительности-и-надежности" tabindex="-1">Улучшения производительности и надежности <a class="header-anchor" href="#улучшения-производительности-и-надежности" aria-label="Permalink to &quot;Улучшения производительности и надежности&quot;">​</a></h3><ul><li><strong>Параллельная обработка</strong> — боты могут параллельно обрабатывать входящие события</li><li><strong>Оптимизация синхронизации</strong> — улучшена производительность синхронизации ботов и тенантов</li><li><strong>Улучшенная обработка ошибок</strong> — структурированные коды ошибок для всех действий с полями <code>code</code>, <code>message</code>, <code>details</code></li><li><strong>Тестовый контур</strong> — отдельное тестовое окружение для проверки изменений перед выкаткой в прод</li></ul><h3 id="документация" tabindex="-1">Документация <a class="header-anchor" href="#документация" aria-label="Permalink to &quot;Документация&quot;">​</a></h3><ul><li><strong>Расширенная документация</strong> — созданы гайды по моделям AI, storage, сценариям, событиям, примерам использования</li><li><strong>Быстрый старт</strong> — отдельный гайд для новых пользователей</li><li><strong>Примеры использования</strong> — практические примеры работы с RAG, платежами, storage и другими функциями</li></ul>',57)])])}const m=o(i,[["render",l]]);export{u as __pageData,m as default};
